const express = require('express');
const app = express();
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/mydatabase', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a schema for the collection
const mySchema = new mongoose.Schema({
  name: String,
  age: Number
});

// Create a model from the schema
const MyModel = mongoose.model('MyModel', mySchema);

// Middleware to parse JSON bodies
app.use(express.json());

// API endpoint to query MongoDB
app.post('/query', async (req, res) => {
  try {
    const filters = req.body;
    
    // Validate input using Joi or another validation library
    const validateFilters = (filters) => {
      if (!filters || typeof filters !== 'object') return false;
      
      for (const key in filters) {
        if (typeof filters[key] !== 'string' && typeof filters[key] !== 'number' && !Array.isArray(filters[key])) return false;
      }
      
      return true;
    };
    
    if (!validateFilters(filters)) {
      res.status(400).send({ error: 'Invalid input' });
      return;
    }
    
    // Apply MongoDB operators to the query
    const query = {};
    for (const key in filters) {
      switch (key) {
        case '$gt':
          query[key] = { $gt: filters[key] };
          break;
        case '$lt':
          query[key] = { $lt: filters[key] };
          break;
        case '$regex':
          query[key] = { $regex: filters[key] };
          break;
        default:
          query[key] = filters[key];
      }
    }
    
    // Execute the query
    const result = await MyModel.find(query);
    
    res.send(result);
  } catch (error) {
    console.error(error);
    res.status(500).send({ error: 'Internal Server Error' });
  }
});

